import{r as l,j as e}from"./index-Lk_4B74N.js";import{P as h}from"./Popup-1_5puC74.js";const u={en:{yearPillar:{title:"Year Pillar",text:`The Year Pillar, based on your birth year, symbolizes your roots—ancestors, grandparents, and the broader external world that surrounds you. Think of it as the background setting of your life's story. Major shifts or "clashes" involving this pillar often signal transformative life events or significant turning points. By observing how the Ten Gods interact here, you can pinpoint where changes may emerge in your journey.`},monthPillar:{title:"Month Pillar",text:'The Month Pillar sets the tone for your personal elemental climate, shaping the overall "seasonal mood" of your life chart. Imagine it as the dominant atmosphere or background vibe influencing your opportunities and challenges. Favorable elements within this pillar tend to attract supportive relationships, prosperity, and positive openings, while unfavorable ones might indicate obstacles to navigate.'},dayPillar:{title:"Day Pillar",text:"The Day Pillar reveals your true self—your core identity, personality, and your closest relationship, particularly your life partner. It's the pillar that highlights your innate qualities, such as creativity, empathy, sociability, responsibility, and emotional resilience. Analyzing your Day Master helps reveal how these characteristics shape your personal journey and interactions."},hourPillar:{title:"Hour Pillar",text:"The Hour Pillar represents your legacy, influencing areas like your children, subordinates, personal creativity, and accumulated wealth. Think of it as the finishing touches that subtly adjust the overall balance of your chart. While the Month Pillar provides the broader seasonal context, the Hour Pillar introduces daily nuances, gently fine-tuning the elemental harmony of your life path."},elements:{title:"Elements",text:`This shows the dominant element in your personal energy (Wood, Fire, Earth, Metal, Water). Each element influences your behavior, health, and compatibility.

• Wood: Growth, expansion, liver, spring.
• Fire: Warmth, upward movement, heart, summer.
• Earth: Stability, nourishment, spleen, late summer.
• Metal: Purification, structure, lungs, autumn.
• Water: Fluidity, wisdom, kidneys, winter.`},tenStars:{title:"Ten Stars",text:`In Chinese Bazi, the Ten Stars are symbolic roles that describe how different energies in your birth chart influence your life. Each represents a specific aspect of your personality, relationships, or life journey—like wealth, authority, support, or self-expression.

The Ten Gods are: Friend, Rob Wealth, Eating God, Hurting Officer, Direct Wealth, Indirect Wealth, Direct Officer, Seven Killings, Direct Resource, and Indirect Resource.

Everyone has a unique mix of these based on their birth details.`},dayMaster:{title:"Day Master (日元)",text:"The Day Master is the elemental energy of your birth day and represents your true personality and core self. It sets the tone for how you respond to life, make decisions, and relate to others."},zodiac:{title:"Zodiac Sign (生肖)",text:"Your Chinese Zodiac sign is based on the year you were born and is linked to one of 12 animals. Each animal reflects personality traits, relationship patterns, and compatibility with others."},yinYang:{title:"Yin-Yang Balance",text:"Yin and Yang energies need to stay in harmony for a healthy, successful life. This chart reveals whether you lean more toward action (Yang) or introspection (Yin), and how to restore balance."},career:{title:"Career Reading",text:"This section reveals your career potential and strengths using ancient Chinese Metaphysics. It helps identify ideal professions, areas for growth, and talents you can develop in your work life."},family:{title:"Family Reading",text:"This section provides insights into your relationship with family members. It reflects emotional dynamics, support systems, and challenges within your family based on your chart."},love:{title:"Love Reading",text:"The Love Reading analyzes your romantic destiny—your emotional needs, ideal partner traits, and relationship patterns. It can also show compatibility and areas to grow in love."},talent:{title:"Talent Reading",text:"Your natural gifts and creative potential are revealed here. This section explores skills, personal strengths, and talents that help you stand out or find your life calling."},wealth:{title:"Wealth Reading",text:"This reading helps you understand your wealth potential, earning capacity, and attitude toward money. It can show how to grow prosperity through work, timing, and alignment with your element."},dailyElement:{title:"Daily Elemental Insight",text:"This section explains how the day’s unique Bazi elements (year, month, day) interact with your chart. It offers context on what energies are dominant or in conflict."},luckyColor:{title:"Lucky Colors",text:`Primary Color: Harmonizes best with your personal element today to boost confidence.
Supporting Color: Adds extra support and emotional grounding to your day.`},fortuneInsight:{title:"Fortune Insight",text:"Brief guidance tailored to your chart about areas like career, money, or emotional well-being. Think of it as a weather forecast for your energy—it tells you when to act and when to be patient."},environment:{title:"Environmental Influences",text:"Your external surroundings affect your energy. This feature helps you adjust lighting, space, or setting to enhance peace, focus, or luck."},luckySign:{title:"Lucky Sign",text:"Your Lucky Sign brings good fortune, helpful people, or lucky events into your life. Look for opportunities when this sign appears in your surroundings."},luckyTime:{title:"Lucky Times",text:"These are the most favorable hours of your day to take action, make important decisions, or start new tasks. Energy flows more smoothly during this window."},luckyDirection:{title:"Lucky Direction",text:"This indicates the direction you should face or travel toward for success, good meetings, or mental clarity. It’s like Feng Shui for your daily movement."}}};function d({defKey:a,style:o,color:i="#F4D73E"}){const[s,n]=l.useState(!1),t=u.en[a];return t?e.jsxs(e.Fragment,{children:[e.jsx("button",{type:"button","aria-label":`Info about ${t.title}`,onClick:r=>{r.preventDefault(),r.stopPropagation(),n(!0)},style:{background:"transparent",border:`1px solid ${i}`,color:i,borderRadius:"50%",width:"16px",height:"16px",fontSize:"10px",fontWeight:"bold",fontFamily:"serif",display:"inline-flex",alignItems:"center",justifyContent:"center",cursor:"pointer",marginLeft:"6px",opacity:.8,padding:0,lineHeight:1,...o},children:"i"}),e.jsx(h,{open:s,title:t.title,message:e.jsx("div",{style:{textAlign:"left",lineHeight:1.6,fontSize:"14px",whiteSpace:"pre-wrap"},children:t.text}),tone:"info",onClose:()=>n(!1),dismissLabel:"Close",closeOnBackdrop:!0})]}):null}export{d as I};
